using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace ApiMcpServer;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource by its unique identifier from the REST API.")]
    public async Task<string> GetResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("List all available resources, optionally filtered by category.")]
    public async Task<string> ListResources(
        [Description("Optional category to filter results")] string? category = null,
        CancellationToken cancellationToken = default)
    {
        var url = category is not null
            ? $"/api/resources?category={Uri.EscapeDataString(category)}"
            : "/api/resources";

        logger.LogInformation("Listing resources with category={Category}", category);
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new resource with the given name and content.")]
    public async Task<string> CreateResource(
        [Description("Display name for the new resource")] string name,
        [Description("Body content of the resource")] string content,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { name, content });
        var httpContent = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        logger.LogInformation("Creating resource {Name}", name);
        var response = await httpClient.PostAsync("/api/resources", httpContent, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

var builder = Host.CreateApplicationBuilder(args);

// Logging MUST go to stderr — stdout is reserved for the JSON-RPC protocol
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

// Register HttpClient with a base address your tools will call
builder.Services.AddHttpClient<ApiMcpServer.ApiTools>(client =>
{
    client.BaseAddress = new Uri("https://api.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

